(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[921],{5143:function(e,t,i){Promise.resolve().then(i.bind(i,5293))},5293:function(e,t,i){"use strict";i.r(t),i.d(t,{default:function(){return r}});var o=i(7821),n=i(8078),a=i(3197);let s={slug:"adhd",title:"Understanding & Managing ADHD",subtitle:"Buffington Family Medicine",accentColor:"#4f46e5",accentColorLight:"#e0e7ff",heroDescription:"ADHD is one of the most common — and most treatable — conditions we manage. This guide covers everything you need to know about your diagnosis, treatment options, medication management, and strategies for thriving with ADHD.",navItems:[{id:"guide",label:"Guide"},{id:"overview",label:"Overview"},{id:"start",label:"Start Here"},{id:"understanding",label:"Understanding ADHD"},{id:"diagnosis",label:"Diagnosis"},{id:"comorbidities",label:"Comorbidities"},{id:"untreated",label:"Why Treat"},{id:"therapy",label:"Therapy"},{id:"medications",label:"Medications"},{id:"stimulants",label:"Stimulants"},{id:"non-stimulants",label:"Non-Stimulants"},{id:"med-expectations",label:"What Medication Can Do"},{id:"expectations",label:"Expectations"},{id:"is-it-working",label:"Is It Working?"},{id:"side-effects",label:"Side Effects"},{id:"refills",label:"Refill Policy"},{id:"lifestyle",label:"Lifestyle Strategies"},{id:"monitoring",label:"Monitoring"},{id:"faqs",label:"FAQs"},{id:"resources",label:"Resources"},{id:"updates",label:"Updates"},{id:"next-steps",label:"Next Steps"}],sections:[{id:"guide",title:"",content:[{type:"callout",variant:"info",title:"How to use this page",body:"Start with the **Start Here** section for your first 30 days. Jump to **FAQs** anytime you have a quick question. Find your **Next Steps** at the bottom. Bookmark this page and come back to it as an ongoing reference — it is always here for you."}]},{id:"overview",title:"Program Overview",content:[{type:"text",body:"Attention-Deficit/Hyperactivity Disorder (ADHD) is a neurodevelopmental condition that affects focus, organization, impulse control, and executive function. It is **not a character flaw** — it is a medical condition with well-established, effective treatments."},{type:"heading",level:3,text:"Most important things to know"},{type:"bullets",items:["**Your first step** is to pick up your prescription and take it as directed — same time each day","**It is normal** to need 1-3 dose adjustments before finding the right fit","**Follow up in 4 weeks** so we can review your response and adjust if needed","**Do not adjust your dose on your own** — call us and we will figure it out together","**Contact our office at (817) 431-9199** if you have chest pain, severe anxiety, or any concerning side effects"]},{type:"callout",variant:"urgent",title:"When to call us",body:"Call **(817) 431-9199** right away if you experience chest pain, severe headache with vision changes, fainting, severe anxiety or panic that does not resolve, or any thoughts of self-harm. Full details are in the **Side Effects** section."},{type:"heading",level:3,text:"What we offer"},{type:"bullets",items:["**Comprehensive evaluation** — we take a thorough history, review symptoms, and rule out other causes before diagnosing","**Personalized medication management** — we find the right medication and dose for your brain, not a one-size-fits-all approach","**Monthly follow-ups required** — controlled substance prescriptions require regular office visits","**Behavioral strategies** — medication works best when combined with practical life management tools","**Ongoing monitoring** — we track your response, adjust as needed, and watch for side effects"]},{type:"callout",variant:"info",title:"You are not broken",body:"ADHD brains are wired differently — not defectively. With the right treatment plan, most patients experience significant improvement in focus, productivity, relationships, and overall quality of life. At Buffington Family Medicine, we have seen many patients describe starting treatment as life-changing."}]},{id:"start",title:"Start Here: Your First 30 Days",content:[{type:"callout",variant:"info",title:"If you only read one thing",body:"**Take your medication as prescribed** at the same time each day. **Track one or two things** (focus and sleep are a great start). **Do not adjust your dose on your own** — call us instead. **Schedule your 4-week follow-up** before you leave the office."},{type:"text",body:"Starting ADHD treatment is a process. The first month is about finding the right medication and dose. Here is what to expect."},{type:"heading",level:3,text:"Your first step"},{type:"text",body:"**Your first step is to pick up your prescription** from the pharmacy. Controlled substances cannot be called in — you will receive a paper or electronic prescription at each visit."},{type:"heading",level:3,text:"Your next steps"},{type:"numbered",items:["**Take your medication as directed** — same time each day, typically in the morning","**Keep a brief daily log** for the first 2 weeks: rate your focus and sleep on a 1-10 scale (add energy, mood, and appetite if you want, but even just two items is helpful)","**Note when the medication kicks in and when it wears off** — this helps us fine-tune your dose and timing","**Schedule your 4-week follow-up** — we will review your log and adjust if needed","**Do not adjust your dose on your own** — if it is not working, call us. We will figure it out together.","**Call our office at (817) 431-9199** if you experience chest pain, severe anxiety, or any concerning side effects"]},{type:"callout",variant:"info",title:"Finding the right dose takes time",body:"Most patients need 1-3 dose adjustments before landing on the right medication and dose. This is completely normal. Do not get discouraged if the first try is not perfect — that is expected and why we schedule close follow-ups."},{type:"callout",variant:"info",title:"You do not need to track perfectly",body:"Do not stress about tracking. You do not need a detailed journal or a perfect record. Just notice a few useful patterns — did you feel more focused? Did you sleep okay? Even rough notes on your phone are enough to help us fine-tune your treatment."}]},{id:"understanding",title:"Understanding ADHD",content:[{type:"text",body:"ADHD affects approximately 4-5% of adults. Many people are not diagnosed until adulthood because they developed coping mechanisms that masked their symptoms — until life demands exceeded their ability to compensate."},{type:"heading",level:3,text:"Three Presentations"},{type:"bullets",items:["**Predominantly Inattentive** — difficulty sustaining focus, easily distracted, forgetful, loses things, struggles with organization and follow-through","**Predominantly Hyperactive-Impulsive** — fidgety, restless, talks excessively, interrupts, difficulty waiting, acts without thinking","**Combined** — features of both inattention and hyperactivity-impulsivity (most common)"]},{type:"heading",level:3,text:"Common Adult Symptoms: Focus & Organization"},{type:"bullets",items:["Chronic difficulty finishing tasks or projects","Procrastination, especially on tasks that are not stimulating","Difficulty with paperwork, bills, administrative tasks","Poor planning and trouble following through on commitments","Difficulty multitasking or switching between tasks"]},{type:"heading",level:3,text:"Common Adult Symptoms: Time & Memory"},{type:"bullets",items:["Losing track of time, running late consistently","Misplacing phone, keys, wallet regularly","Difficulty listening in conversations — mind wanders"]},{type:"heading",level:3,text:"Common Adult Symptoms: Emotions & Behavior"},{type:"bullets",items:["Impulsive spending, eating, or decision-making","Feeling restless, needing to stay busy","Emotional dysregulation — quick to frustration, rejection sensitivity","Hot temper or low frustration tolerance","Frequent mood swings","Underperforming at work despite being intelligent and capable"]},{type:"callout",variant:"info",title:"ADHD is not about intelligence",body:"ADHD has nothing to do with how smart you are. Many highly intelligent people have ADHD — in fact, the gap between their potential and their output is often what brings them to seek help."}]},{id:"diagnosis",title:"How We Diagnose ADHD",content:[{type:"text",body:"There is no single test for ADHD. At Buffington Family Medicine, diagnosis is based on a comprehensive clinical evaluation."},{type:"heading",level:3,text:"Our Evaluation Includes"},{type:"numbered",items:["**Detailed symptom history** — current symptoms, duration, and how they affect your daily life","**Childhood history** — ADHD symptoms must have been present before age 12 (though they may not have been recognized)","**Screening questionnaires** — standardized tools like the ASRS (Adult ADHD Self-Report Scale)","**Physical exam and basic labs** — to rule out thyroid problems, low blood sugar, seizure disorders, and other medical causes","**Rule out other conditions** — anxiety, depression, sleep disorders, brain injury, substance use, and medication side effects can all mimic ADHD","**Functional impairment** — symptoms must cause real problems in at least two areas of life (work, relationships, finances, etc.)"]},{type:"text",body:"We do not require formal neuropsychological testing for most adults. A thorough clinical interview by an experienced provider is the gold standard for ADHD diagnosis."}]},{id:"comorbidities",title:"Conditions That Often Accompany ADHD",content:[{type:"text",body:"ADHD rarely exists in isolation. More than **60% of adults with ADHD** have at least one coexisting condition. Recognizing these is important because they affect how we approach treatment."},{type:"bullets",items:["**Anxiety disorders** — the most common comorbidity. Generalized anxiety, social anxiety, and panic disorder frequently co-occur with ADHD",'**Depression** — chronic underperformance, relationship struggles, and feeling "broken" can lead to depression over time',"**Substance use disorders** — untreated ADHD significantly increases the risk of self-medicating with alcohol, nicotine, or other substances","**Learning disabilities** — difficulty with reading, writing, or math that is separate from the attention issues","**Sleep disorders** — difficulty falling asleep, restless sleep, and delayed sleep phase are extremely common in ADHD","**Mood dysregulation** — quick to anger, rejection sensitivity, emotional volatility that goes beyond typical ADHD impulsivity"]},{type:"callout",variant:"info",title:"Why this matters for treatment",body:"Comorbid conditions can change which ADHD medication we choose, what dose we start with, and what additional treatments we recommend. For example, if you have significant anxiety alongside ADHD, we may start with a lower stimulant dose or add an anxiety medication. Always tell your provider about **all** of your symptoms — not just the ones you think are ADHD."}]},{id:"untreated",title:"What Happens When ADHD Goes Untreated",content:[{type:"text",body:"ADHD is not a condition you simply outgrow or push through with willpower. Without treatment, it can have significant consequences across many areas of life."},{type:"bullets",items:["**Work and career** — chronic underperformance, job loss, difficulty advancing despite ability","**Financial problems** — impulsive spending, missed bills, difficulty with budgeting and long-term planning","**Relationships** — conflict with partners, friends, and family due to forgetfulness, emotional reactivity, and difficulty following through","**Substance misuse** — significantly higher rates of alcohol, nicotine, and drug use as a form of self-medication","**Driving safety** — higher rates of traffic violations and car accidents due to inattention and impulsivity","**Mental health** — increased risk of depression, anxiety, and low self-esteem from years of struggling without support","**Education** — incomplete degrees, underachievement relative to intellectual ability"]},{type:"callout",variant:"info",title:"It is never too late",body:"Many patients come to us after years or decades of struggling without a diagnosis. Getting diagnosed and treated as an adult is just as valid and effective as childhood diagnosis. Our team will work with you wherever you are in your journey. Most patients wish they had done it sooner."}]},{id:"therapy",title:"Therapy & Counseling",content:[{type:"text",body:"Medication is the most effective single treatment for ADHD, but the **best outcomes come from combining medication with therapy or coaching**. Medication clears the fog; therapy builds the systems and habits."},{type:"heading",level:3,text:"Cognitive Behavioral Therapy (CBT)"},{type:"text",body:"CBT is the most evidence-based therapy for adult ADHD. It focuses on practical skills rather than exploring your childhood. A therapist trained in ADHD-specific CBT can help you with:"},{type:"bullets",items:["**Time management and planning** — building systems that work with your brain","**Organization** — creating routines for tasks you chronically avoid","**Emotional regulation** — managing frustration, rejection sensitivity, and impulsivity",'**Negative thought patterns** — addressing the "I\'m lazy" or "I\'m stupid" beliefs that years of struggling can create',"**Procrastination** — understanding why you avoid and building strategies to start"]},{type:"heading",level:3,text:"Other helpful approaches"},{type:"bullets",items:["**ADHD coaching** — a practical, action-oriented approach focused on accountability, goal-setting, and habit-building","**Couples or family therapy** — ADHD affects everyone in the household. Therapy can improve communication and reduce conflict","**Mindfulness training** — growing evidence supports mindfulness meditation for improving attention and emotional regulation in ADHD","**Support groups** — connecting with other adults who have ADHD can reduce isolation and provide practical tips (CHADD offers both in-person and online groups)"]},{type:"callout",variant:"info",title:"We can refer you",body:"If you are interested in therapy or coaching, let your provider know. We can recommend therapists in the Flower Mound area who specialize in adult ADHD. Not every therapist is experienced with ADHD — a specialist makes a significant difference."}]},{id:"medications",title:"ADHD Medications",content:[{type:"text",body:"Medication is the most effective treatment for ADHD. There are two main categories: **stimulants** and **non-stimulants**. At Buffington Family Medicine, we will work together to find the right one for you."},{type:"text",body:"Stimulant medications are first-line treatment and work for approximately 70-80% of patients. If stimulants are not a good fit, non-stimulant options are available."},{type:"callout",variant:"info",title:"Controlled substance classification",body:"Most ADHD medications are Schedule II controlled substances. This means they require a new prescription each month (no automatic refills), must be picked up from the pharmacy, and require regular follow-up visits with your provider. This is federal law, not our policy. See the **Refill Policy** section for details on scheduling and timing."}]},{id:"stimulants",title:"Stimulant Medications",content:[{type:"text",body:"Stimulants work by increasing dopamine and norepinephrine in the brain — the neurotransmitters responsible for focus, motivation, and executive function."},{type:"heading",level:3,text:"Methylphenidate-Based (Ritalin Family)"},{type:"table",headers:["Medication","Duration","Notes"],rows:[["Ritalin / Methylphenidate IR","3-4 hours","Short-acting, taken 2-3x daily"],["Ritalin LA / Metadate CD","6-8 hours","Intermediate-acting"],["Concerta","10-12 hours","Extended-release, once daily"],["Jornay PM","~12 hours","Taken at bedtime, active by morning"]]},{type:"heading",level:3,text:"Amphetamine-Based (Adderall Family)"},{type:"table",headers:["Medication","Duration","Notes"],rows:[["Adderall IR","4-6 hours","Short-acting, taken 1-2x daily"],["Adderall XR","10-12 hours","Extended-release, once daily"],["Vyvanse (lisdexamfetamine)","12-14 hours","Pro-drug, smooth onset, lower abuse potential"],["Mydayis","16 hours","Triple-bead extended-release"]]},{type:"heading",level:3,text:"How We Choose"},{type:"bullets",items:["We typically start with a **low dose of a long-acting stimulant** and titrate up","If one class does not work well, we try the other (methylphenidate vs. amphetamine)","Some patients benefit from a **long-acting morning dose plus a short-acting afternoon booster**","We consider your schedule, insurance coverage, and any history of substance use"]}]},{id:"non-stimulants",title:"Non-Stimulant Options",content:[{type:"text",body:"Non-stimulant medications may be appropriate if stimulants cause significant side effects, if you have certain cardiac conditions, a history of substance abuse, or severe anxiety alongside ADHD."},{type:"table",headers:["Medication","Class","Notes"],rows:[["Strattera (atomoxetine)","NRI","Takes 4-6 weeks for full effect. 24-hour coverage. Not a controlled substance."],["Wellbutrin (bupropion)","NDRI","Also treats depression. Off-label for ADHD. Not a controlled substance."],["Qelbree (viloxazine)","NRI","FDA-approved for ADHD. Serotonin modulating activity. Not a controlled substance."],["Intuniv (guanfacine ER)","Alpha-2 agonist","Helps with impulsivity and emotional regulation. Often used as add-on."]]},{type:"callout",variant:"info",title:"Non-stimulants work differently",body:"Unlike stimulants, which work within 30-60 minutes, non-stimulants take weeks to reach full effectiveness. Do not judge them by the first few days. Give them the full trial period your provider recommends."}]},{id:"med-expectations",title:"What Medication Can and Cannot Do",content:[{type:"text",body:"ADHD medication is powerful, but it is not a cure-all. Understanding what it can and cannot do will help you set realistic expectations and get the most out of your treatment."},{type:"heading",level:3,text:"What medication CAN help with"},{type:"bullets",items:["**Sustaining focus** on tasks, conversations, and reading","**Following through** on plans and commitments","**Reducing impulsivity** — pausing before acting or speaking","**Quieting mental noise** — less racing, scattered thinking","**Improving working memory** — holding information while you use it","**Emotional regulation** — less intense frustration and reactivity"]},{type:"heading",level:3,text:"What medication CANNOT do on its own"},{type:"bullets",items:["**Create routines** — you still need to build systems and habits","**Organize your space** — it helps you start, but you choose what to do","**Fix years of avoidance** — backlogged tasks still need attention","**Replace skills you never learned** — time management, planning, and prioritization may need coaching or practice","**Make boring tasks interesting** — it helps you push through them, but they will still feel boring"]},{type:"callout",variant:"info",title:"Think of it this way",body:"Medication gives your brain the ability to focus and follow through. **You still choose where to point that focus.** The most successful patients pair medication with practical strategies — even small ones like a phone alarm for appointments or a designated spot for keys."}]},{id:"expectations",title:"What to Expect from Treatment",content:[{type:"heading",level:3,text:"Week 1-2: Starting Out"},{type:"bullets",items:["You may notice improved focus within the first 1-2 days on a stimulant","Appetite suppression is common — eat breakfast before your medication kicks in","You might feel slightly more alert or energized than usual",'Some patients report a mild "crash" as the medication wears off — this often improves with dose adjustments']},{type:"heading",level:3,text:"Week 3-4: Fine-Tuning"},{type:"bullets",items:["By now you should have a sense of whether the medication is helping","Bring your daily log to your follow-up — it helps us make precise adjustments","We may increase the dose, change the timing, or switch medications entirely","It is normal to need adjustments — this is the process working as intended"]},{type:"heading",level:3,text:"Month 2-3: Stabilization"},{type:"bullets",items:["Most patients are on a stable, effective dose by month 2-3","Side effects that appeared early often diminish","You should notice meaningful improvement in focus, organization, and follow-through","This is when behavioral strategies become especially powerful — the medication clears the path, and the strategies build the habits"]},{type:"callout",variant:"info",title:"What good treatment feels like",body:'The right medication at the right dose should make you feel like a **clearer, calmer version of yourself** — not wired, not flat, not robotic. If you feel "off," tell us. The goal is not perfection — it is consistent, meaningful improvement in daily functioning.'}]},{id:"is-it-working",title:"How to Tell If Your Medication Is Working",content:[{type:"text",body:"Before your follow-up visit, take a moment to notice whether any of these have improved. You do not need to check every box — even a few meaningful changes mean the medication is having an effect."},{type:"checklist",items:["I can finish tasks I start more often than before","I lose my phone, keys, or wallet less frequently","I am able to sit through a conversation or meeting without my mind wandering as much","I feel less overwhelmed by my to-do list","I can start tasks without as much procrastination","I am less impulsive in conversations or decisions","I feel calmer or less restless during the day","I am keeping up with bills, emails, or paperwork better than before","My mood is more stable — less frustration or emotional reactivity","People around me have noticed a positive difference"]},{type:"callout",variant:"info",title:"Bring this to your visit",body:"Reviewing this checklist before your appointment gives us concrete information to work with. If none of these have improved, that is also useful — it tells us the current medication or dose may not be the right fit, and we can adjust."}]},{id:"side-effects",title:"Side Effects & Management",content:[{type:"text",body:"Most side effects are mild and manageable. Many improve within the first 1-2 weeks as your body adjusts."},{type:"heading",level:3,text:"Common Side Effects (Stimulants)"},{type:"table",headers:["Side Effect","What to Do"],rows:[["Decreased appetite","Eat a good breakfast before medication kicks in. Have protein-rich snacks available. Eat a solid dinner when it wears off."],["Difficulty falling asleep","Take medication earlier in the day. Avoid caffeine after noon. Establish a consistent bedtime routine."],["Dry mouth","Stay hydrated. Sugar-free gum or mints can help."],["Mild headache","Usually resolves in the first week. Stay hydrated. OTC pain relief is fine."],["Increased heart rate","Mild increase is normal. Report resting HR consistently above 100 or palpitations."],["Irritability as it wears off","May indicate dose needs adjustment. A small afternoon booster dose can help smooth the transition."]]},{type:"callout",variant:"urgent",title:"When to call immediately",body:"Contact us at **(817) 431-9199** or go to the ER if you experience: chest pain or pressure, severe headache with vision changes, shortness of breath, fainting, severe anxiety or panic that does not resolve, or any thoughts of self-harm."}]},{id:"refills",title:"Controlled Substance Refill Policy",content:[{type:"callout",variant:"info",title:"Quick summary: Refills at a glance",body:"**New prescription required every month** (no auto-refills). **You must be seen in the office** to continue receiving prescriptions. **Schedule your next visit before you leave** so you never run out. **Lost or stolen medications cannot be replaced early.**"},{type:"text",body:"ADHD stimulant medications are Schedule II controlled substances. Federal and state regulations require specific procedures for prescribing these medications."},{type:"heading",level:3,text:"What This Means for You"},{type:"bullets",items:["**A new prescription is required each month** — no automatic refills are allowed","**You must be seen in the office regularly** to continue receiving prescriptions","**Prescriptions cannot be called or faxed to the pharmacy** — they are sent electronically via EPCS (Electronic Prescribing for Controlled Substances)","**Lost or stolen medications cannot be replaced early** — store your medication securely","**We check the Texas PDMP** (Prescription Drug Monitoring Program) at each visit as required by law","**Pick up prescriptions promptly** — some pharmacies return prescriptions not picked up within a certain timeframe"]},{type:"heading",level:3,text:"Scheduling Tips"},{type:"numbered",items:["**Schedule your next appointment before you leave each visit** so you never run out","**If you need to reschedule**, do so as early as possible — last-minute cancellations may result in a gap in medication","**Plan ahead for vacations or travel** — we can sometimes adjust timing but cannot prescribe extra medication"]},{type:"heading",level:3,text:"Pharmacy Issues"},{type:"text",body:"If your pharmacy says they do not have your medication in stock, call us. We can send the prescription to a different pharmacy. Do not wait until you have run out to address this."},{type:"callout",variant:"info",title:"We are on your side",body:"These rules exist because of federal regulations, not because we doubt you. Our team understands it can be frustrating. Our goal is to keep your treatment uninterrupted — and the best way to do that is to stay on schedule with your visits."}]},{id:"lifestyle",title:"Lifestyle Strategies for ADHD",content:[{type:"text",body:"Medication treats the core symptoms, but behavioral strategies help you build systems that work with your brain instead of against it."},{type:"heading",level:3,text:"Organization & Productivity"},{type:"bullets",items:["**Use one calendar for everything** — phone calendar with alerts, not paper planners you will lose","**Set alarms and reminders** for medications, appointments, deadlines, and transitions",'**Break tasks into small, concrete steps** — "clean the kitchen" becomes "load dishwasher, wipe counters, take out trash"']},{type:"bullets",items:["**Use the 2-minute rule** — if something takes less than 2 minutes, do it now","**Designate a landing pad** — one spot for keys, wallet, phone, and anything you need to grab on the way out","**Body doubling** — work alongside someone (even virtually) for accountability and focus"]},{type:"heading",level:3,text:"Sleep"},{type:"bullets",items:["**Sleep is non-negotiable** — poor sleep makes ADHD dramatically worse","Aim for 7-9 hours in a consistent schedule (same bedtime, same wake time)","Take stimulant medication early enough that it does not interfere with sleep","Reduce screen time 30-60 minutes before bed","If insomnia persists, tell your provider — we may adjust medication timing or add a sleep aid"]},{type:"heading",level:3,text:"Exercise"},{type:"bullets",items:["**Regular exercise is one of the most effective non-medication treatments for ADHD**","Even 20-30 minutes of moderate activity improves focus, mood, and impulse control","Find something you enjoy — consistency matters more than intensity","Morning exercise before medication can help jumpstart your day"]},{type:"heading",level:3,text:"Nutrition"},{type:"bullets",items:["**Eat a protein-rich breakfast** before your medication kicks in — this is the most important meal of the day for ADHD patients","Keep easy, healthy snacks accessible for when appetite is low","Stay hydrated — dehydration worsens focus and can amplify medication side effects","Limit caffeine, especially in the afternoon — it can interact with stimulants and disrupt sleep"]}]},{id:"monitoring",title:"Ongoing Monitoring",content:[{type:"text",body:"Regular follow-up is essential for safe, effective ADHD treatment. Here is what our team tracks at every visit."},{type:"table",headers:["What We Monitor","Why","Frequency"],rows:[["Symptom response","Is the medication working? At what dose?","Every visit"],["Side effects","Are they manageable? Do we need to adjust?","Every visit"],["Blood pressure & heart rate","Stimulants can raise both slightly","Every visit"],["Weight","Appetite suppression can cause weight loss","Every visit"],["Sleep quality","Medication timing affects sleep","Every visit"],["Mood & anxiety","ADHD meds can sometimes worsen anxiety","Every visit"],["PDMP check","Required by Texas law for controlled substances","Every visit"]]},{type:"callout",variant:"info",title:"Bring your daily log",body:"The more data you bring to your visit, the better we can fine-tune your treatment. Even a simple 1-10 rating of focus and sleep each day gives us valuable information. It does not need to be perfect — just helpful."}]}],faqs:[{question:"Is ADHD a real medical condition?",answer:"Yes. ADHD is one of the most well-researched conditions in medicine, with decades of peer-reviewed evidence supporting its diagnosis and treatment. Brain imaging studies show clear differences in dopamine signaling and executive function networks in people with ADHD."},{question:"Can adults develop ADHD or is it only a childhood condition?",answer:"ADHD is a neurodevelopmental condition that begins in childhood, but many adults are not diagnosed until later in life. Symptoms must have been present before age 12, though they may not have been recognized or may have been masked by coping strategies."},{question:"Will I need to take medication forever?",answer:"Not necessarily. Some patients take medication long-term and benefit greatly. Others use it for a period to build habits and systems, then taper off. This is a personal decision made with your provider based on your needs and response."},{question:"Are ADHD medications addictive?",answer:"When taken as prescribed under medical supervision, ADHD stimulants have a low risk of addiction. In fact, untreated ADHD carries a higher risk of substance abuse than treated ADHD. We monitor closely and follow all prescribing guidelines."},{question:"Can I take ADHD medication if I have anxiety?",answer:"Many patients have both ADHD and anxiety. Sometimes treating ADHD reduces anxiety (because you are functioning better). Sometimes stimulants can temporarily worsen anxiety. We often address both conditions and may combine ADHD medication with an anti-anxiety treatment."},{question:"Why can't you just call in my refill?",answer:"Schedule II controlled substances cannot be refilled or called in by federal law. A new prescription must be issued each month, and regular follow-up visits are required. This is not our policy — it is federal regulation."},{question:"What if my medication stops working?",answer:"This can happen. Sometimes a dose adjustment is needed, sometimes switching to a different medication helps. Factors like sleep, stress, diet, and hormonal changes can also affect medication effectiveness. Tell your provider — there are always options."},{question:"Can I drink coffee while taking a stimulant?",answer:"Moderate caffeine is usually fine, but be mindful. Caffeine and stimulants both increase heart rate and can worsen anxiety or insomnia. We recommend limiting caffeine and avoiding it after noon, especially while finding the right dose."},{question:"Do I take medication on weekends and holidays?",answer:"This depends on your situation and your provider's recommendation. Some patients take medication daily for consistent symptom management. Others take 'medication holidays' on days when focus demands are lower. Discuss this with your provider."},{question:"What happens if I miss a dose?",answer:"If it is still early in the day, you can take it. If it is afternoon or later, skip it and take your next dose on schedule. Do not double up. Missing an occasional dose is not harmful — the medication does not build up in your system like an antidepressant."}],resources:[{title:"ADHD Daily Tracking Log",description:"Simple daily log for focus, mood, appetite, and sleep",type:"pdf"},{title:"CHADD — National ADHD Organization",description:"Education, advocacy, and support for ADHD",type:"link"},{title:"ADDitude Magazine",description:"Practical strategies and research updates for ADHD",type:"link"}],updates:[{title:"ADHD Hub launched",date:"March 2026",summary:"Your ADHD resource hub is now live with medication guides, lifestyle strategies, and refill policy information."}],nextSteps:[{title:"Schedule an Appointment",description:"Book your next follow-up or initial evaluation.",action:"Call (817) 431-9199"},{title:"Refill Request",description:"Schedule your monthly visit to receive your next prescription.",action:"Schedule Visit"},{title:"Download Tracking Log",description:"Track your daily focus, mood, appetite, and sleep to bring to your visit.",action:"Get Tracking Log"},{title:"Message Your Provider",description:"Have a question between visits? Reach out through the patient portal.",action:"Send Message"}]};function r(){return(0,o.jsx)(n.Suspense,{children:(0,o.jsx)(a.oP,{config:s})})}}},function(e){e.O(0,[197,115,364,744],function(){return e(e.s=5143)}),_N_E=e.O()}]);